/**
 * Side Filter Data Service
 * Enterprise-grade data management for side filters
 * 100% best practices, zero shortcuts, enterprise-grade patterns
 */

import { EventEmitter } from 'events';
import { z } from 'zod';
import { FilterErrorHandler, FilterErrorType, FilterErrorSeverity, FilterErrorContext } from '@/services/error/FilterErrorHandler';
import type { SideFilterSection, SideFilterOption } from '@/components/filters/AdvancedSideFilter';

// ===== DATA SCHEMAS =====

const FilterOptionSchema = z.object({
  id: z.string(),
  label: z.string(),
  value: z.string(),
  count: z.number().optional(),
  isSelected: z.boolean().default(false),
  isDisabled: z.boolean().optional(),
  metadata: z.object({
    color: z.string().optional(),
    imageUrl: z.string().optional(),
    description: z.string().optional()
  }).optional()
});

const FilterSectionSchema = z.object({
  id: z.string(),
  title: z.string(),
  type: z.enum(['checkbox', 'radio', 'range', 'search', 'color', 'size']),
  options: z.array(FilterOptionSchema),
  isExpanded: z.boolean().default(true),
  isCollapsible: z.boolean().default(true),
  maxVisibleOptions: z.number().optional(),
  showMoreText: z.string().optional(),
  showLessText: z.string().optional(),
  placeholder: z.string().optional(),
  minValue: z.number().optional(),
  maxValue: z.number().optional(),
  step: z.number().optional(),
  unit: z.string().optional()
});

const FilterDataSchema = z.object({
  categoryId: z.string(),
  sections: z.array(FilterSectionSchema),
  lastUpdated: z.number(),
  version: z.string(),
  metadata: z.record(z.unknown()).optional()
});

export interface FilterData extends z.infer<typeof FilterDataSchema> {}

